from contextlib import asynccontextmanager
from fastapi import FastAPI, HTTPException
from fastapi.responses import JSONResponse, HTMLResponse
from pydantic import BaseModel, Field
from dotenv import load_dotenv
from pipeline import run_research_pipeline

load_dotenv()

class ResearchRequest(BaseModel):
    topic: str = Field(..., min_length=5, max_length=500, description="The research topic or question to investigate", example="What are the latest advancements in quantum computing?")
    max_iterations: int = Field(default=3, ge=1, le=5, description="Maximum research-critique loops (1-5)")

class ResearchResponse(BaseModel):
    topic: str
    final_report: str
    sources: list[str]
    iterations_completed: int
    sources_count: int
    status: str
    duration_seconds: float
    mlflow_run_id: str | None = None

class HealthResponse(BaseModel):
    status: str
    model: str
    max_iterations: int
    mlflow_tracking_uri: str

@asynccontextmanager
async def lifespan(app: FastAPI):
    print("[API] Multi-Agent Research System starting up...")
    yield
    print("[API] Shutting down...")

app = FastAPI(
    title="Multi-Agent Research System",
    description="""
    An autonomous multi-agent research pipeline built with LangChain and LangGraph.
    ## How it works
    1. **Researcher Agent** searches the web using Tavily API
    2. **Critic Agent** evaluates findings and flags gaps
    3. **Writer Agent** synthesizes a structured markdown report
    4. All runs are tracked in **MLflow**
    The system iterates until findings are sufficient or max_iterations is reached.
    """,
    version="1.0.0",
    lifespan=lifespan,
    docs_url=None,
    redoc_url=None,
)

